                    return PJNATH_ESTUNDUPATTR;
                }
                has_msg_int = PJ_TRUE;

            } else if (attr_type == PJ_STUN_ATTR_FINGERPRINT) {
                if (has_fingerprint) {
                    /* Already has FINGERPRINT */
                    if (p_response) {
                        pj_stun_msg_create_response(pool, msg,
