				return GF_OK;
			}
			ctx->cts += ctx->framelen;
		}
	}
	gf_filter_pid_drop_packet(ctx->ipid);

	if (ctx->probe_data) {
		gf_free(ctx->probe_data);
		ctx->probe_data = NULL;
		ctx->probe_data_size = 0;
	}
	return GF_OK;
}

